parameters.jsCode:
const body = $input.first().json;
return [{
  json: {
    testName: body.test_name || body.testName || 'Unknown Test',
    suiteName: body.suite_name || body.suiteName || 'Unknown Suite',
    errorMessage: body.error_message || body.errorMessage || body.message || '',
    stackTrace: body.stack_trace || body.stackTrace || '',
    duration: body.duration || 0,
    retryCount: body.retry_count || body.retryCount || 0,
    branch: body.branch || 'unknown',
    commitSha: body.commit_sha || body.commitSha || '',
    runUrl: body.run_url || body.runUrl || '',
    repository: body.repository || 'unknown',
    timestamp: body.timestamp || new Date().toISOString()
  }
}];

parameters.jsonBody:
={
  "model": "claude-sonnet-4-20250514",
  "max_tokens": 1024,
  "messages": [{
    "role": "user",
    "content": "You are a senior QA engineer analyzing test failures. Classify this failure into exactly ONE category: FLAKY (intermittent/timing/race condition), BUG (real application defect), or INFRA (environment/network/CI infrastructure issue).

Respond in this exact JSON format:
{"category": "FLAKY|BUG|INFRA", "confidence": 0.0-1.0, "root_cause": "one-line root cause", "analysis": "2-3 sentence detailed analysis", "recommended_action": "what to do next"}

Test: {{ $json.testName }}
Suite: {{ $json.suiteName }}
Error: {{ $json.errorMessage }}
Stack Trace: {{ $json.stackTrace }}
Duration: {{ $json.duration }}ms
Retry Count: {{ $json.retryCount }}
Branch: {{ $json.branch }}"
  }]
}

